import{_ as o,o as i,c as a,ag as d}from"./chunks/framework.DTiDeF2Q.js";const _=JSON.parse('{"title":"Аліаси конфігурації | Dotfiles (UK)","titleTemplate":":title","description":"Короткі команди конфігурації. Огляд для Dotfiles v0.2.495. Сумісно з macOS, Linux та WSL через Dotfiles.","frontmatter":{"title":"Аліаси конфігурації | Dotfiles","description":"Короткі команди конфігурації. Огляд для Dotfiles v0.2.495. Сумісно з macOS, Linux та WSL через Dotfiles.","lang":"uk-UA","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Аліаси конфігурації | Dotfiles preview","canonical":"/uk/aliases/configuration/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Аліаси конфігурації","pageType":"docs","schemaType":"WebPage","permalink":"/uk/aliases/configuration/"},"headers":[],"relativePath":"uk/aliases/configuration/index.md","filePath":"uk/aliases/configuration/index.md","lastUpdated":1773010926000}'),t={name:"uk/aliases/configuration/index.md"};function l(c,e,r,s,n,u){return i(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="аліаси-конфігураціі" tabindex="-1">Аліаси конфігурації <a class="header-anchor" href="#аліаси-конфігураціі" aria-label="Permalink to &quot;Аліаси конфігурації&quot;">​</a></h1><p>Короткі команди конфігурації.</p><p>Ця сторінка знайомить з однією групою аліасів та її поширеними скороченнями команд. Прочитайте її спочатку, щоб зрозуміти угоди про іменування, очікувані вхідні дані та безпечні шаблони виконання. Потім відкрийте довідковий додаток для повного переліку команд та точного синтаксису. Ці аліаси зменшують повторний набір та зберігають послідовну поведінку робочого процесу на macOS, Linux та WSL.</p><h2 id="коли-використовувати" tabindex="-1">Коли використовувати <a class="header-anchor" href="#коли-використовувати" aria-label="Permalink to &quot;Коли використовувати&quot;">​</a></h2><p>Використовуйте цю сторінку перед щоденною роботою в оболонці, коли вам потрібні передбачувані шаблони команд.</p><h2 id="що-включено" tabindex="-1">Що включено <a class="header-anchor" href="#що-включено" aria-label="Permalink to &quot;Що включено&quot;">​</a></h2><ul><li>Аліаси: 11</li><li>Допоміжні функції: 0</li><li>Файли джерел: 1</li></ul><h2 id="швидкі-приклади" tabindex="-1">Швидкі приклади <a class="header-anchor" href="#швидкі-приклади" aria-label="Permalink to &quot;Швидкі приклади&quot;">​</a></h2><ul><li><code>dot</code> → <code>$HOME/.local/bin/dot</code></li><li><code>eddot</code> → <code>${EDITOR} $HOME/.dotfiles</code></li><li><code>edit_bash_profile</code> → <code>${EDITOR} $HOME/.bash_profile</code></li><li><code>edit_bashrc</code> → <code>${EDITOR} $HOME/.bashrc</code></li><li><code>edit_current_directory</code> → <code>${EDITOR} .</code></li><li><code>edit_docker_compose</code> → <code>${EDITOR} docker-compose.yml</code></li><li><code>edit_git_config</code> → <code>${EDITOR} $HOME/.gitconfig</code></li><li><code>edit_git_ignore</code> → <code>${EDITOR} $HOME/.gitignore</code></li><li><code>edit_ssh_config</code> → <code>${EDITOR} $HOME/.ssh/config</code></li><li><code>edit_zsh_profile</code> → <code>${EDITOR} $HOME/.zsh_profile</code></li><li><code>edit_zshrc</code> → <code>${EDITOR} $HOME/.zshrc</code></li></ul><h2 id="наступнии-крок" tabindex="-1">Наступний крок <a class="header-anchor" href="#наступнии-крок" aria-label="Permalink to &quot;Наступний крок&quot;">​</a></h2><p>Відкрити повний перелік:</p>',11)])])}const f=o(t,[["render",l]]);export{_ as __pageData,f as default};
